<script setup lang="ts">
definePageMeta({ layout: false })
const config = useRuntimeConfig(); const email = ref('admin@laotour.la'); const password = ref('laotour2026'); const error = ref(''); const logged = ref(false); const places = ref<any[]>([]); const users = ref<any[]>([]); const form = reactive({ title:'', slug:'', excerpt:'', description:'', province:'', category:'Nature', image:'', status:'published' })
async function login() { try { const result:any = await $fetch(`${config.public.apiBase}/auth/login`, { method:'POST', body:{ email:email.value, password:password.value } }); localStorage.setItem('lao_token', result.accessToken); logged.value=true; await load() } catch { error.value='Email or password is incorrect.' } }
const authHeaders = () => ({ Authorization: `Bearer ${localStorage.getItem('lao_token')}` })
async function load() { places.value = await $fetch(`${config.public.apiBase}/places`); users.value = await $fetch(`${config.public.apiBase}/auth/users`, { headers: authHeaders() }) }
async function addPlace() { await $fetch(`${config.public.apiBase}/places`, { method:'POST', headers: authHeaders(), body:form }); Object.assign(form, { title:'',slug:'',excerpt:'',description:'',province:'',category:'Nature',image:'',status:'published' }); await load() }
onMounted(() => { if (localStorage.getItem('lao_token')) { logged.value=true; load() } })
</script>
<template><div class="min-h-screen bg-[#f7f8f5] p-5 text-[#173a2b] lg:p-8"><div v-if="!logged" class="mx-auto mt-20 max-w-md rounded-[2rem] bg-white p-9 surface"><NuxtLink to="/" class="font-display text-2xl">← Lao Tour</NuxtLink><p class="mt-10 text-xs font-bold uppercase tracking-[.2em] text-[#9d7f32]">Control room</p><h1 class="mt-2 font-display text-4xl">Welcome back.</h1><p class="mt-2 text-[#648075]">Sign in to curate Laos.</p><form class="mt-8 space-y-4" @submit.prevent="login"><input v-model="email" type="email" class="w-full rounded-xl border-0 bg-[#f1f4ef] px-4 py-3" placeholder="Email"/><input v-model="password" type="password" class="w-full rounded-xl border-0 bg-[#f1f4ef] px-4 py-3" placeholder="Password"/><p v-if="error" class="text-sm text-red-600">{{ error }}</p><button class="w-full rounded-xl bg-[#173a2b] py-3 font-semibold text-white">Sign in</button></form></div><div v-else class="mx-auto max-w-7xl"><header class="flex items-center justify-between"><div><p class="text-xs font-bold uppercase tracking-[.2em] text-[#9d7f32]">Admin dashboard</p><h1 class="mt-2 font-display text-4xl">Good morning, curator.</h1></div><NuxtLink to="/" class="rounded-full border border-[#d2dbd0] px-4 py-2 text-sm">View website ↗</NuxtLink></header><div class="mt-9 grid gap-6 lg:grid-cols-[1.25fr_.75fr]"><section class="rounded-3xl bg-white p-6 surface"><div class="flex items-center justify-between"><h2 class="font-display text-3xl">Places</h2><span class="rounded-full bg-[#e7eee5] px-3 py-1 text-sm">{{ places.length }} published</span></div><div class="mt-5 divide-y divide-[#e7eee5]"><div v-for="place in places" :key="place.id" class="flex items-center gap-4 py-4"><img :src="place.image" class="h-14 w-14 rounded-xl object-cover"/><div class="flex-1"><p class="font-semibold">{{ place.title }}</p><p class="text-sm text-[#6b8278]">{{ place.province }} · {{ place.category }}</p></div><span class="text-xs text-emerald-700">{{ place.status }}</span></div></div><div class="mt-6 rounded-2xl bg-[#e7eee5] p-4"><p class="text-xs font-bold uppercase tracking-[.15em] text-[#9d7f32]">Users</p><div v-for="user in users" :key="user.id" class="mt-3 flex justify-between text-sm"><span>{{ user.name }}<small class="ml-2 text-[#6b8278]">{{ user.email }}</small></span><span class="capitalize">{{ user.role }}</span></div></div></section><section class="rounded-3xl bg-[#173a2b] p-6 text-white"><p class="text-xs font-bold uppercase tracking-[.2em] text-[#e9d486]">New destination</p><h2 class="mt-2 font-display text-3xl">Add a place</h2><form class="mt-6 space-y-3" @submit.prevent="addPlace"><input v-model="form.title" required placeholder="Place name" class="admin-input"/><input v-model="form.slug" required placeholder="URL slug" class="admin-input"/><input v-model="form.province" required placeholder="Province" class="admin-input"/><select v-model="form.category" class="admin-input"><option>Nature</option><option>Culture</option><option>Adventure</option><option>Food</option></select><input v-model="form.image" required placeholder="Image URL" class="admin-input"/><textarea v-model="form.excerpt" required placeholder="Short introduction" class="admin-input min-h-20"/><textarea v-model="form.description" required placeholder="Full story" class="admin-input min-h-24"/><button class="w-full rounded-xl bg-[#e4c66d] py-3 font-semibold text-[#173a2b]">Publish place</button></form></section></div></div></div></template>
<style scoped>.admin-input{width:100%;border-radius:.75rem;background:rgba(255,255,255,.12);padding:.75rem 1rem;color:white;outline:none}.admin-input::placeholder{color:rgba(255,255,255,.55)}.admin-input option{color:#173a2b}</style>
